    15→  getTransactionGainType,
    16→  getFormattedPointsValue,
    17→  getFormattedHighlightText,
    18→  getFormattedPointsValueForMarketplace,
    19→  getPaymentTypeLabel,
    20→  getMarketplaceTitle,
    21→  getCleanedImageUrl,
    22→} from './utils';
    23→import { MarketplaceContentData, MarketplaceItemData, STATUS_COLORS } from './Models';
